-- migrations/076_phase29d_dp_payroll_cash_legs.sql
-- Phase 29-D: Close the $130K SOCF reconciliation gap.
--
-- Root cause analysis:
--   40 Mercury "Dangerous Pretze..." outflows ($118K) were unrecognized by categorizer
--   (truncated counterparty doesn't match regex). 18 of these have an existing posted
--   bookkeeper PPE JE that already records the cash leg (DR Expense / CR Mercury all-in-one).
--   22 have NO posted PPE Mercury CR — they're cash legs the bookkeeper either missed
--   (2 Jan-May orphans) or skipped because they switched to accrual-only mode (20 Jun-Oct).
--
-- Foundational fix:
--   1. Reverse the pre_sync_adjustment Payroll Payable plug (Phase 23-Payroll patch)
--      — that plug assumed bookkeeper accruals had NO cash leg. Now we know they DO,
--      and the cash legs are these Mercury DP txns.
--   2. For 18 matched DP: mark mercury_transactions.is_reconciled=1, link to PPE JE
--   3. For 22 unmatched DP: post DR Payroll Payable / CR Mercury Checking (cash leg)
--
-- NOTE: This makes Mercury Checking GL no longer match actual bank statements at
-- intermediate month-ends (new CRs reduce balance). Migration 077 (next) re-runs
-- Phase 29 monthly reconciliation against the new GL state.

-- Step 0: Unlock all closed periods (Phase 23-FY2025 closes Dec 2025)
UPDATE closed_periods SET unlocked_at=datetime('now'), unlock_reason='Phase 29-D: DP payroll cash legs + pre_sync_adjustment reversal', unlocked_by='session_29d' WHERE unlocked_at IS NULL;

-- Step 1: Reverse pre_sync_adjustment Payroll Payable plug (Phase 23-Payroll)
UPDATE journal_entries SET status='reversed', notes=COALESCE(notes,'') || ' | Phase 29-D reversed 2026-05-19; bookkeeper accruals DO have cash legs (Mercury DP txns)' WHERE id='23-payroll-payable-drain';

-- Step 2: Mark 18 matched DP txns as reconciled (already have PPE cash legs)
UPDATE mercury_transactions SET is_reconciled=1, matched_journal_entry_id='584abe38-65a8-4d93-9afa-832b7e02498f' WHERE id='ca0f6854-b2aa-4cc4-9d2d-6bbadfc42c77';
